blocks.code:
h1, h2, h3, blockquote {
  text-wrap: balance; /* even lines for short runs */
}

p {
  text-wrap: pretty; /* no orphaned last words */
}

.icon {
  transition:
    opacity 0.25s var(--ease),
    transform 0.25s var(--ease),
    filter 0.25s var(--ease);
}
.icon.leaving {
  opacity: 0;
  transform: scale(0.6);
  filter: blur(3px);
}

@keyframes enter {
  from {
    opacity: 0;
    transform: translateY(8px);
    filter: blur(8px);
  }
}

[data-animate] {
  animation: enter 0.8s var(--ease) both;
  animation-delay: calc(var(--stagger, 0) * 100ms);
}

// loud: exit mirrors the entrance
exit={{ x: "calc(-100% - 4px)" }}

// quiet: exits demand less attention
exit={{ opacity: 0, filter: "blur(4px)" }}

.outer {
  --pad: 8px;
  --inner-r: 12px;
  padding: var(--pad);
  border-radius: calc(var(--inner-r) + var(--pad)); /* 20px */
}
.inner {
  border-radius: var(--inner-r);
}

.card {
  box-shadow:
    0 0 0 1px rgba(0, 0, 0, 0.06),
    0 1px 2px -1px rgba(0, 0, 0, 0.06),
    0 2px 4px 0 rgba(0, 0, 0, 0.04);
  transition: box-shadow 0.3s var(--ease);
}
.card:hover {
  box-shadow:
    0 0 0 1px rgba(0, 0, 0, 0.08),
    0 1px 2px -1px rgba(0, 0, 0, 0.08),
    0 2px 4px 0 rgba(0, 0, 0, 0.06);
}

img {
  outline: 1px solid rgba(0, 0, 0, 0.1);
  outline-offset: -1px; /* sits just inside the edge */
}

/* dark mode */
.dark img {
  outline-color: rgba(255, 255, 255, 0.1);
}
